import { ChatFlow } from 'flowise-components';

const detectMemoryTruncation = (chatflow: ChatFlow) => {
  const memoryNodes = chatflow.nodes.filter(node => node.data.type === 'ConversationBufferMemory');

  return memoryNodes.some(node => {
    const config = node.data.config as any;
    const maxTokens = config?.maxTokenLimit || 4000;
    const currentLength = chatflow.edges
      .filter(edge => edge.target === node.id)
      .reduce((acc, edge) => {
        const sourceNode = chatflow.nodes.find(n => n.id === edge.source);
        return acc + (sourceNode?.data.outputLength || 0);
      }, 0);

    return currentLength > maxTokens * 0.8;
  });
};

const detectContextHandoffLoss = (chatflow: ChatFlow) => {
  const agentNodes = chatflow.nodes.filter(node => 
    node.data.type?.includes('Agent') || node.data.type === 'AgentExecutor'
  );

  const handoffIssues = [];

  agentNodes.forEach((sourceAgent, i) => {
    const downstreamNodes = chatflow.edges
      .filter(edge => edge.source === sourceAgent.id)
      .map(edge => chatflow.nodes.find(n => n.id === edge.target));

    downstreamNodes.forEach(targetNode => {
      if (targetNode?.data.type?.includes('Agent') && !hasMemoryEdge(chatflow, sourceAgent.id, targetNode.id)) {
        handoffIssues.push({ source: sourceAgent.id, target: targetNode.id });
      }
    });
  });

  return handoffIssues;
};

const hasMemoryEdge = (chatflow: ChatFlow, sourceId: string, targetId: string) => {
  return chatflow.edges.some(edge => 
    edge.source === sourceId && 
    edge.target === targetId && 
    edge.data?.type === 'memory'
  );
};

const detectVectorMemoryDrift = (chatflow: ChatFlow) => {
  const vectorNodes = chatflow.nodes.filter(node => 
    node.data.type?.includes('VectorStore') || node.data.type === 'Retriever'
  );

  return vectorNodes.some(vectorNode => {
    const upstreamNodes = getUpstreamNodes(chatflow, vectorNode.id);
    const hasMemoryInput = upstreamNodes.some(node => 
      node.data.type?.includes('Memory') || node.data.type === 'ConversationBufferWindowMemory'
    );

    const config = vectorNode.data.config as any;
    const refreshInterval = config?.refreshInterval;

    return !hasMemoryInput || (refreshInterval && refreshInterval > 1000 * 60 * 5); // > 5 minutes
  });
};

const getUpstreamNodes = (chatflow: ChatFlow, targetId: string) => {
  return chatflow.edges
    .filter(edge => edge.target === targetId)
    .map(edge => chatflow.nodes.find(n => n.id === edge.source))
    .filter(Boolean) as any[];
};

