import { BasicLLMChatNode } from 'flowise-components';

export class MemorySyncNode extends BasicLLMChatNode {
  async constructChain(fields: any) {
    const chain = await super.constructChain(fields);

    return {
      ...chain,
      memorySync: async (input: any, memory: any) => {
        // Persist memory to shared store
        await this.sharedMemoryStore.set('global_context', memory);

        // Forward to next agent
        const enrichedInput = {
          ...input,
          chat_history: memory,
          global_context: await this.sharedMemoryStore.get('global_context')
        };

        return chain.call(enrichedInput);
      }
    };
  }
}

