import { Vex } from '@vex_dev/sdk';
import { ChatFlow, INode } from 'flowise-components';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

// Add Vex callback to Flowise server
export const addVexMemoryGuard = (app: any) => {
  app.post('/api/v1/prediction/:id', async (req: any, res: any) => {
    // Scan chatflow before execution
    const chatflow = req.body.chatflow as ChatFlow;
    const issues = await vex.scan.chatflow(chatflow, {
      focus: 'memory-management',
      thresholds: { maxTokens: 3500, handoffCoverage: 0.95 }
    });

    if (issues.length > 0) {
      await vex.autoFix.chatflow(chatflow, issues);
      console.log('Vex fixed memory issues:', issues);
    }

    // Runtime monitoring
    const handle = vex.monitor.chatflow(chatflow.id, {
      onMemoryTruncation: (node: INode) => {
        console.log(`Memory truncated at ${node.id}`);
      },
      onContextLoss: (handoff: {from: string, to: string}) => {
        vex.injectMemorySync(handoff.from, handoff.to);
      }
    });

    // Original Flowise execution
    const result = await originalPredictionHandler(req, res);
    handle.cleanup();

    return result;
  });
};
